INSERT INTO words (word, category_id, position, tag, zh, en, example_en, example_zh, synonyms) VALUES
  ('between', 'op', 26, 'OP', '在两者之间；介于', 'in the space or relation separating two things', 'The road runs between the school and the market.', '这条路在学校和市场之间。', '[{"w":"before","def":"before: 相关的动作或关系词","vs":"与 between 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"before\" / \"between\" 的替换练习"},{"w":"by","def":"by: 可帮助扩展句型的基础词","vs":"与 between 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"by\" / \"between\" 的替换练习"},{"w":"down","def":"down: 同一组 Basic English 操作词","vs":"与 between 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"down\" / \"between\" 的替换练习"}]'),
  ('by', 'op', 27, 'OP', '被；通过；在旁边；不迟于', 'near, through the action of, or not later than', 'The book was written by a young teacher.', '这本书是一位年轻教师写的。', '[{"w":"between","def":"between: 相关的动作或关系词","vs":"与 by 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"between\" / \"by\" 的替换练习"},{"w":"down","def":"down: 可帮助扩展句型的基础词","vs":"与 by 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"down\" / \"by\" 的替换练习"},{"w":"from","def":"from: 同一组 Basic English 操作词","vs":"与 by 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"from\" / \"by\" 的替换练习"}]'),
  ('down', 'op', 28, 'OP', '向下；在低处', 'toward or in a lower place', 'The ball rolled down the hill.', '球从山坡上滚下来。', '[{"w":"by","def":"by: 相关的动作或关系词","vs":"与 down 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"by\" / \"down\" 的替换练习"},{"w":"from","def":"from: 可帮助扩展句型的基础词","vs":"与 down 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"from\" / \"down\" 的替换练习"},{"w":"in","def":"in: 同一组 Basic English 操作词","vs":"与 down 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"in\" / \"down\" 的替换练习"}]'),
  ('from', 'op', 29, 'OP', '从；来自；离开某处', 'show the starting point, source, or origin', 'This letter came from my sister.', '这封信来自我妹妹。', '[{"w":"down","def":"down: 相关的动作或关系词","vs":"与 from 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"down\" / \"from\" 的替换练习"},{"w":"in","def":"in: 可帮助扩展句型的基础词","vs":"与 from 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"in\" / \"from\" 的替换练习"},{"w":"off","def":"off: 同一组 Basic English 操作词","vs":"与 from 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"off\" / \"from\" 的替换练习"}]'),
  ('in', 'op', 30, 'OP', '在……里面；在某段时间内', 'inside a place, condition, or period', 'The apples are in the basket.', '苹果在篮子里。', '[{"w":"from","def":"from: 相关的动作或关系词","vs":"与 in 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"from\" / \"in\" 的替换练习"},{"w":"off","def":"off: 可帮助扩展句型的基础词","vs":"与 in 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"off\" / \"in\" 的替换练习"},{"w":"on","def":"on: 同一组 Basic English 操作词","vs":"与 in 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"on\" / \"in\" 的替换练习"}]');
